CST Activity Config.rulesText:
SKIPCHECK;
FEEDSTRINGS;

# Driver Percentage Share per Activity → Service Line.
# Input Volume per (activity, Input, service_line) is the basis for all activities.
# For activities with basis = 'Input', volumes are direct user entry.
# For driver-based activities (e.g. BEDDAYS), volumes are entered per SL to represent
# the relative driver quantities by service line.
# Only fires where CST Driver = 'Input'.
['Driver Percentage Share'] = N:
  IF( !CST Driver @<> 'Input', CONTINUE,
    IF( ['Input Volume'] = 0, 0,
      ['Input Volume'] /
      DB('CST Activity Config', !GBL Period, !GBL Version, !CST Activity, 'Input', 'Total Service Lines', 'Input Volume')
      * 100
    )
  );

FEEDERS;

# Feed Driver Percentage Share — fired by stored Input Volume at (activity, Input, service_line).
['CST Driver':'Input','CST Activity Config Measure':'Input Volume'] =>
  DB('CST Activity Config', !GBL Period, !GBL Version, !CST Activity, 'Input', !CST Service Line, 'Driver Percentage Share');

# Feed Apportionment Rate in Stage 3 — Cost Centre not in Activity Config so use Total Cost Centres consolidation.
['CST Driver':'Input','CST Activity Config Measure':'Driver Percentage Share'] =>
  DB('CST Activity to Service Line Apportionment', !GBL Period, !GBL Version,
     !CST Service Line, !CST Activity, 'GBL Cost Centre':'Total Cost Centres', 'Apportionment Rate');

CST Activity to Activity Config.rulesText:
SKIPCHECK;
FEEDSTRINGS;

# Driver Percentage Share: normalise Driver Value to percentage per source Activity.
# Same pattern as CST Pool to Pool Config — Python reads Driver Value directly and
# normalises in the solver, but Driver Percentage Share is available for PAW review.
['Driver Percentage Share'] = N:
  IF(
    DB('CST Activity to Activity Config', !GBL Period, !GBL Version,
       !CST Activity, 'Total Activity Dest', 'Input', 'Driver Value') = 0, 0,
    ['Driver Value'] /
    DB('CST Activity to Activity Config', !GBL Period, !GBL Version,
       !CST Activity, 'Total Activity Dest', 'Input', 'Driver Value')
    * 100
  );

FEEDERS;

# Feed Driver Percentage Share — fired when Driver Value is stored.
['CST Activity to Activity Config Measure':'Driver Value'] =>
  DB('CST Activity to Activity Config', !GBL Period, !GBL Version,
     !CST Activity, !CST Activity Dest, 'Input', 'Driver Percentage Share');
